import{_ as a,o as n,c as o,a3 as t}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"211. Conversion Of Unused Sick Leave To Annual Leave","description":"","frontmatter":{"title":"211. Conversion Of Unused Sick Leave To Annual Leave","eba":"Mental Health Services 2024-2028","topics":["leave","personal-leave","annual-leave"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/leave/211-conversion-of-unused-sick-leave-to-annual-leave.md","filePath":"ebas/mental-health/management-admin/leave/211-conversion-of-unused-sick-leave-to-annual-leave.md"}'),s={name:"ebas/mental-health/management-admin/leave/211-conversion-of-unused-sick-leave-to-annual-leave.md"};function l(r,e,i,d,c,h){return n(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="_211-conversion-of-unused-sick-leave-to-annual-leave" tabindex="-1">211. Conversion Of Unused Sick Leave To Annual Leave <a class="header-anchor" href="#_211-conversion-of-unused-sick-leave-to-annual-leave" aria-label="Permalink to &quot;211. Conversion Of Unused Sick Leave To Annual Leave&quot;">​</a></h1><p>Royal Children&#39;s Hospital This clause only applies to Management and Administrative Officers at Royal Children’s Hospital classified under Part 2 of <a href="/eba/ebas/mental-health/schedules/07-management-and-administrative-officers-classifications.html">Schedule 7</a> of this Agreement.</p><p><strong>211.1</strong> If an Employee is not absent as provided for in <a href="/eba/ebas/mental-health/common-terms/leave/38A-personal-leave.html">clause 38A</a> of this Agreement, they will be credited with one (1) day of annual leave for every two (2) days of personal leave not taken and the Employee’s personal leave balance shall be reduced in a proportion of two to one for each additional day of annual leave so credited.</p><p><strong>211.2</strong> If the Employee advises the Employer, in writing, not less than four (4) weeks prior to the conclusion of any one year, they may elect to retain the unused personal leave credits as accrued personal leave.</p><p><strong>211.3</strong> For the purposes of this clause, “day” means the number of hours in a shift that an Employee is ordinarily rostered to work, and “days” has a corresponding meaning.</p><p><strong>211.4</strong> For the purposes of this clause, “in any one year” shall mean the completion of the pay period after 14 November 1995.</p><p><strong>211.5</strong> An Employee may only convert personal leave under this clause if, and to the extent that, the Employee’s accrued personal leave exceeds the minimum personal leave which has accrued under, or is recognised under, the National Employment Standards (NES). The Employee’s remaining accrued entitlements (after conversion) must be at least 15 days.</p><p>Plain language terms: holidays, vacation, recreation leave, holiday pay.</p>',8)])])}const p=a(s,[["render",l]]);export{m as __pageData,p as default};
